+    fn invariant_runtime_mode_exactly_one_state_true() {
+        let modes = [
+            RuntimeMode::Live,
+            RuntimeMode::ExplicitOffline,
+            RuntimeMode::DegradedOffline,
+            RuntimeMode::Refused,
+        ];
+        for mode in &modes {
+            let sum = (mode.is_authoritative() as u8)
+                + (mode.is_offline() as u8)
+                + (mode.is_refused() as u8);
+            assert_eq!(
